-- DETAIL GUARDZ Dirt Lock Car Wash Insert – Bucket Filter for 3–8 Gallon Round Pails – Traps Debris, Prevents Swirl Marks – Self-Locking Rubber Grips, Venturi Flow, Cleaning Tool (USA)
INSERT INTO products (
  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12d934c1-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ Dirt Lock Car Wash Insert – Bucket Filter for 3–8 Gallon Round Pails – Traps Debris, Prevents Swirl Marks – Self-Locking Rubber Grips, Venturi Flow, Cleaning Tool', NULL, 'dirt-lock-car-wash-insert', '24.99', NULL, NULL, NULL, 'Patented Venturi bucket filter that traps grit and debris at the bottom of your wash bucket — keeping your mitt in cleaner water to prevent swirl marks and scratches on your vehicle''s paint.', NULL, 'DETAIL GUARDZ DIRT LOCK CAR WASH BUCKET INSERT

Our patented design utilizes the motion of your hand to pump and trap debris underneath the screen. The Dirt Lock has a complex Venturi filtering system that manipulates the flow of water in a downward direction. This allows dirt particles to collect underneath the screen without a way for it to re-enter into the clean water. In short, every time you pump your hand in the bucket you are cycling the dirt underneath the screen and replenishing clean water above to help prevent swirl-marks and scratches on the painted surface.

ONE Dirt Lock will filter your wash water like you have never seen before. Protect your car and eliminate the main cause of swirl marks on your paintwork! Proudly Made In Canada.

Fits inside nearly any 3, 4, 5, 6, 7 or 8 gallon standard round wash pail with its flexible, self-adjusting, rubber locking grips.

VENTURI EFFECT: The Dirt Lock manipulates the flow of water by creating a high pressure underneath the filter and a low pressure above. This results in a tunneling effect and pushes the debris safely underneath the screen and provides much cleaner water above to reuse on your vehicle''s paintwork.

AUTOMATIC SELF-LOCKING: Simply push the Dirt Lock inside almost any 3–8 gallon round wash bucket and it will automatically adjust itself for the perfect fit. The Dirt Lock is molded from a special plastic resin that sinks like an anchor in the bucket.

THE ULTIMATE SCRATCH-PROTECTION: It''s locked and loaded with every detail possible to ensure your vehicle''s finish is maintained to the highest standards.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (black) B07CKC4M9D/1. Hero Image.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (blue) B07CKLPJZR/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (blue) B07CKLPJZR/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (blue) B07CKLPJZR/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (blue) B07CKLPJZR/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (blue) B07CKLPJZR/5. Product Uses.webp"]', '{"red":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (red) B07CKG1VCH/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (red) B07CKG1VCH/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (red) B07CKG1VCH/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/Dirt Lock/Dirt Lock (red) B07CKG1VCH/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lo