-- DETAIL GUARDZ Dirt Lock Scrub Wall 180/360 – Vertical Cleaning Tool for Brushes, Mitts (USA)
INSERT INTO products (
  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12d9f202-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ Dirt Lock Scrub Wall 180/360 – Vertical Cleaning Tool for Brushes, Mitts', NULL, 'dirt-lock-scrub-wall', '20.99', NULL, NULL, NULL, 'Vertical cleaning extension for the Dirt Lock bucket filter — snaps in instantly, isolates debris behind the screen, and gives mitts & brushes a full 3D scrubbing surface without sacrificing bucket space.', NULL, 'DETAIL GUARDZ DIRT LOCK SCRUB WALL 180/360 SYSTEM ATTACHMENT

The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock''s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall. The debris is now behind the scrub wall screen and is pumped and trapped below the filter to provide cleaner, filtered water for reuse. Whether you move your wash media forward, backward, left, right, up or down in the bucket, debris is quickly trapped behind the screen and pumped out of harms way with the Dirt Lock Scrub Wall 180/360 system.

VERTICAL EXTENSION OF THE DIRT LOCK''S PRESSURIZED CLEANING POWER: Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space.

ATTACHES INTO DIRT LOCK BUCKET FILTER: The Dirt Lock bucket filter allows you to attach the Scrub Wall 180/360 or any of our other detailing tools when needed. When you''re finished, simply detach it!

Each Scrub Wall kit contains 180 degrees of coverage, simply connect two 180 kits together for full 360 degree bucket coverage.

OUR MOST ADVANCED BUCKET FILTERING SYSTEM: With the addition of our scrub wall 180/360 attachment, it takes the product to another level by flushing out your wash mitt and tools more thoroughly, resulting in even cleaner wash media and the ability to cycle the debris even quicker underneath the screen. Proudly Made In Canada.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/1. Hero Image.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/5. Product Uses.webp"]', '{"red":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/5. Product Uses.webp"],"black":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/5. Product Uses.webp"],"white":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/2. Product Features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/3. How it works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/5. Product Uses.webp"]}', NULL, '{"main":{"url":"https://www.youtube.com/embed/wgR1NE6h6Zk","title":"DETAIL GUARDZ Dirt Lock Scrub Wall 180/360","description":"Maximize your cleaning power with the Scrub Wall. This video shows how to install and use the 180/360 configurations."},"additional":[{"url":"https://www.youtube.com/embed/2S1_ebwMuZs","title":"Scrub Wall In Action","subtitle":"Vertical cleaning technology"},{"url":"https://www.youtube.com/embed/dgeAFI_K6sI","title":"Scrub Wall Teaser","subtitle":"Product highlights"}]}', 'Detailing-Accessories', '12d2523b-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ', NULL, 'USA-FD75DC3A', 'USA-FD75DC3A', NULL, NULL, '4.50', 828, 0, 'Out of Stock', NULL, NULL, '["VERTICAL CLEANING BOOST FOR DIRT LOCK FILTERS: Transforms your bucket into a 3D cleaning station. The Scrub Wall extends the Dirt Lock system upward, giving wash mitts and brushes more surface to agitate grime while reducing debris recirculation.","KEEPS WASH WATER CLEANER: Using directional water flow, the Scrub Wall helps isolate contaminants. Dirt is pulled behind the screen and sent below the filter, preventing grime from returning to your mitt or paintwork.","180° EXPANDABLE DESIGN, 360° UPGRADEABLE: Includes one 180-degree wall; connect a second Scrub Wall for full 360-degree wraparound. Maximizes cleaning contact without taking up extra space.","FITS ALL STANDARD ROUND PAILS: Compatible with most 3–8 gallon wash buckets with a base diameter between 10.2–10.72 inches. Maintains full water capacity while improving wash quality.","SNAPS SECURELY INTO BUCKET FILTER BASE: Quickly attaches to the existing Dirt Lock insert without tools. Modular design lets you add or remove the wall as needed."]', '["Dirt Lock Bucket Filter","3–8 Gallon Round Pails","Wash Mitts","Wheel Brushes"]', '{"asin":"B09CRX2D31","brand":"DETAIL GUARDZ","weight":"12.3 ounces","material":"High-Grade Plastic Resin","dimensions":"12.75 x 7.5 x 3 inches","manufacturer":"DETAIL GUARDZ Canada","bestSellersRank":"#36,333 in Automotive, #18 in Automotive Buckets, Grit Guards & Kits","itemModelNumber":"DG-DL-SW180-WHT","dateFirstAvailable":"August 1, 2021"}', '{"features":[{"alt":"Vertical Cleaning Power","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL.jpg","label":"VERTICAL EXTENSION OF THE DIRT LOCK''S PRESSURIZED CLEANING POWER","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space."},{"alt":"Attaches Into Filter","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL 1.jpg","label":"ATTACHES INTO DIRT LOCK BUCKET FILTER","description":"The Dirt Lock bucket filter allows you to attach the Scrub Wall 180/360 or any of our other detailing tools when needed. When your finished, simply detach it!\n\nEach Scrub Wall kit contains 180 degrees of coverage, simply connect two 180 kits together for full 360 degree bucket coverage."},{"alt":"Advanced Filtering","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL 2.jpg","label":"OUR MOST ADVANCED BUCKET FILTERING SYSTEM","description":"The Dirt Lock bucket filter is extremely powerful on it''s own. With the addition of our scrub wall 180/360 attachment, it takes the product to another level by flushing out your wash mitt and tools more thoroughly, resulting in even cleaner wash media and the ability to cycle the debris even quicker underneath the screen with the added vertical extension."}],"heroImage":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION LARGE.jpg","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall. The debris is now behind the scrub wall screen and is pumped and trapped below the filter to provide cleaner, filtered water for reuse. Whether you move your wash media forward, backward, left, right, up or down in the bucket, debris is quickly trapped behind the screen and pumped out of harms way with the Dirt Lock Scrub Wall 180/360 system.","heroImageAlt":"Dirt Lock Scrub Wall System","secondarySection":{"items":[{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 1.jpg","title":"DIRT LOCK PAD WASHER SYSTEM ATTACHMENT","description":"Clean your polishing pads safely and gently within seconds! Simply attach the pad washer attachment into your Dirt Lock bucket filter, place your dirty pads onto the supplied hook and loop handle, spray with our pad cleaner to break down polish and wax, pump pads on the attachment and your done within seconds!"},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 2.jpg","title":"DIRT LOCK SCRUB AND PUMP SYSTEM ATTACHMENT","description":"Use the Scrub And Pump attachment for added cleaning power with your Dirt Lock bucket filter. Simply push the attachment into place and use it to scrub wash mitts, brushes, hand applicator pads and more! The Dirt Lock scrub and pump attachment works on a spring loaded system to pump cleaner water up and cycle dirty debris safely underneath the screen and out of harms way."},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 3.jpg","title":"DIRT LOCK SCRUB WALL 180/360 SYSTEM ATTACHMENT","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall."}],"title":"ADDITIONAL ATTACHMENTS"}}', '[{"sku":"DIRT-LOCK-SW180-WHITE","asin":"B09CRX2D31","name":"White","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (white)/1. Hero Image.webp","price":20.99,"stock":0,"value":"white","in_stock":0,"amazon_sku":"DIRT LOCK-SW180 WHITE"},{"sku":"DIRT-LOCK-SW180-BLACK","asin":"B09CRZD82Q","name":"Black","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (black)/1. Hero Image.webp","price":20.99,"stock":0,"value":"black","in_stock":0,"amazon_sku":"DIRT LOCK-SW180 BLACK"},{"sku":"DIRT-LOCK-SW180-RED","asin":"B0D66Z4DJB","name":"Red","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/Scrub Wall/Dirt Lock Scrub Wall (red)/1. Hero Image.webp","price":20.99,"stock":0,"value":"red","in_stock":0,"amazon_sku":"DIRT LOCK-SW180 RED"}]', '[{"date":"2 days ago","name":"John Doe","title":"Perfect Product!","images":["https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1519641471654-76ce0107ad1b?w=200&h=200&fit=crop"],"rating":5,"comment":"This is hands down the best car care product I''ve ever purchased. The quality is exceptional and it works exactly as advertised. Installation was super easy and it''s made such a difference in my detailing routine. Highly recommend to anyone serious about car care!","verified":1,"helpfulCount":24},{"date":"1 week ago","name":"Sarah Miller","title":"Great value for money","rating":4,"comment":"Really impressed with the quality. Works great and is very durable. The only reason I''m giving 4 stars instead of 5 is that shipping took a bit longer than expected, but the product itself is fantastic. Would definitely buy again.","verified":1,"helpfulCount":12},{"date":"2 weeks ago","name":"Mike Rodriguez","title":"Professional Quality","images":["https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?w=200&h=200&fit=crop"],"rating":5,"comment":"As a professional detailer, I''m always skeptical of new products. But this exceeded my expectations. The build quality is solid, it performs consistently, and my clients have noticed the difference. Already ordered 3 more for my team. A must-have tool!","verified":1,"helpfulCount":45},{"date":"3 weeks ago","name":"Emily Kim","title":"Exceeded expectations!","rating":5,"comment":"I was hesitant to spend this much on a car care product, but I''m so glad I did. It''s made my weekly car washing so much easier and more effective. The results speak for themselves - my car looks showroom fresh every time. Worth every penny!","verified":1,"helpfulCount":18}]', '[{"count":535,"stars":5,"percentage":65},{"count":140,"stars":4,"percentage":17},{"count":66,"stars":3,"percentage":8},{"count":33,"stars":2,"percentage":4},{"count":49,"stars":1,"percentage":6}]', 'Premium', 'https://www.amazon.com/dp/B09CRX2D31', NULL, NULL, 'USA', 0, 'us', 0, 1, '"2026-03-29T22:32:31.000Z"', '"2026-04-01T23:47:02.000Z"'
