  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12dabe9c-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ The Dirt Lock Scrub and Pump Attachment for Car Wash Bucket Filter', NULL, 'dirt-lock-scrub-pump', '16.99', NULL, NULL, NULL, 'Spring-loaded scrub and pump attachment for the Dirt Lock bucket filter — scrubs your mitt while pumping clean water up and cycling debris safely under the screen.', NULL, 'DETAIL GUARDZ DIRT LOCK SCRUB AND PUMP SYSTEM

Use the Scrub And Pump attachment for added cleaning power with your Dirt Lock bucket filter. Simply push the attachment into place and use it to scrub wash mitts, brushes, hand applicator pads and more! The Dirt Lock scrub and pump attachment works on a spring loaded system to pump cleaner water up and cycle dirty debris safely underneath the screen and out of harms way. The soft rounded scrubbing ridges allow you to scrub and pump away dirt and grime safely under the screen. This is the ultimate bucket filtering system to further enhance the Dirt Locks cleaning power and help ensure your vehicle is safe from swirl-marks and scratches! Proudly Made In Canada.

PUSH ACTIVATED PUMP: Simply push down on the pump and a heavy stream of cleaner water will blast upward. This allows you to scrub and pump away the debris safely under the Dirt Lock bucket filter.

ATTACHES INTO DIRT LOCK BUCKET FILTER: The Dirt Lock bucket filter allows you to attach the scrub and pump or any of our other detailing tools when needed. When you''re finished, simply detach it!

OUR MOST ADVANCED BUCKET FILTERING SYSTEM: The Dirt Lock bucket filter is extremely powerful on its own. With the addition of our scrub and pump attachment, it takes the product to another level by flushing out your wash mitt and tools more thoroughly, resulting in even cleaner wash media and the ability to cycle the debris even quicker underneath the screen with the added pump system.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/The Dirt Lock Scrub and Pump black.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/The Dirt Lock Scrub and Pump black.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/Scrub & Pump Images/1.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/Scrub & Pump Images/2.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/Scrub & Pump Images/3.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/Scrub & Pump Images/4.webp"]', NULL, NULL, '{"main":{"url":"https://www.youtube.com/embed/Ck9pNdgxRp4","title":"DETAIL GUARDZ Dirt Lock Scrub and Pump Attachment","description":"Experience the power of filtered water. The Scrub and Pump attachment ensures you are always using the cleanest possible water on your vehicle."},"additional":[]}', 'Detailing-Accessories', '12d2523b-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ', NULL, 'USA-68913A7B', 'USA-68913A7B', NULL, NULL, '4.50', 236, 0, 'Out of Stock', NULL, NULL, '["Use in your wash bucket to clean your mitt as you dunk!","Soft rounded scrubbing ridges allow you to scrub and pump away debris!","Works perfectly with wash mitts, brushes, hand applicators and more!","The ultimate scratch-protection system for your vehicle!","Patented venturi spring design pumps clean water into your wash mitt, brushes, hand applicators and more, then traps the unwanted debris!"]', '["Dirt Lock Bucket Filter","3-8 Gallon Round Pails"]', '{"asin":"B08FTK9PJJ","brand":"DETAIL GUARDZ","weight":"9.2 ounces","material":"Industrial Grade Plastic & Metal","dimensions":"7.28 x 6.5 x 4.33 inches","manufacturer":"DETAIL GUARDZ Canada","bestSellersRank":"#139,629 in Automotive, #57 in Automotive Buckets, Grit Guards & Kits, #254 in Cleaning Kits","itemModelNumber":"DG-DL-SAP-WHT","dateFirstAvailable":"August 1, 2020"}', '{"features":[{"alt":"Push Activated Pump","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/ABOUT SECTION SMALL.jpg","label":"PUSH ACTIVATED PUMP","description":"Simply push down on the pump and a heavy stream of cleaner water will blast upward. This allows you to scrub and pump away the debris safely under the Dirt Lock bucket filter."},{"alt":"Attaches Into Filter","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/ABOUT SECTION SMALL 1.jpg","label":"ATTACHES INTO DIRT LOCK BUCKET FILTER","description":"The Dirt Lock bucket filter allows you to attach the scrub and pump or any of our other detailing tools when needed. When your finished, simply detach it!"},{"alt":"Advanced Filtering","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub & Pump Images-20260312T173939Z-1-001/ABOUT SECTION SMALL 2.jpg","label":"OUR MOST ADVANCED BUCKET FILTERING SYSTEM","description":"The Dirt Lock bucket filter is extremely powerful on it''s own. With the addition of our scrub and pump attachment, it takes the product to another level by flushing out your wash mitt and tools more thoroughly, resulting in even cleaner wash media and the ability to cycle the debris even quicker underneath the screen with the added pump system."}],"heroImage":"https://detailguardz.s3.us-east-1.amazonaw