-- The Detail Guardz - Dirt Lock Pad Washer System With Attachment (USA)
INSERT INTO products (
  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12db84ef-2b91-11f1-ac48-767b5e3bd9b8', 'The Detail Guardz - Dirt Lock Pad Washer System With Attachment', NULL, 'dirt-lock-pad-washer-attachment', '58.99', NULL, NULL, NULL, 'SEMA Award-winning pad washer system that clicks into your Dirt Lock bucket filter — cleans all polishing pads from 1" to 10" safely and gently within seconds using the patented Venturi spring design.', NULL, 'DETAIL GUARDZ DIRT LOCK PAD WASHER SYSTEM ATTACHMENT

The Dirt Lock pad washer attachment clicks into your Dirt Lock bucket filter to clean any polishing pads safely and gently within seconds! Clean your foam, wool, microfiber, buffing bonnets and more within the blink of an eye.

HOW TO USE: Simply insert the pad washer attachment into your Dirt Lock bucket filter and place into a bucket with clean water. Attach your dirty pads onto the supplied hook and loop handle and pump up and down on the attachment for about 15-20 seconds. Clean water will blast inside the pad and flush out any unwanted chemicals to create a perfectly clean polishing pad!

WORKS WITH ANY 1" TO 10" PADS: The Dirt Lock pad washer system will quickly and gently clean any polishing pad from 1 inch all the way to 10 inches. This system replicates a gentle hand wash, so it does not tear or damage your polishing pad.

SEMA AWARD WINNING: The Dirt Lock pad washer system works so well it won the SEMA global media awards! Feel confident knowing you are receiving a rigorously tested and proven pad washer system that will last for years!

The Dirt Lock pad washer attachment is made from industrial grade plastic and metal for extreme durability. Proudly Made In Canada.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/0.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/0.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/1.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/2.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/3.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/4.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/5.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section large.jpg","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section small.jpg","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section small1.jpg","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section small2.jpg"]', NULL, NULL, '{"main":{"url":"https://www.youtube.com/embed/_ZHI-xV6XLg","title":"DETAIL GUARDZ Dirt Lock Pad Washer System","description":"See how the SEMA Award-winning Dirt Lock Pad Washer System cleans your polishing pads safely and gently in seconds."},"additional":[{"url":"https://www.youtube.com/embed/rmmq1jVdY40","title":"Detail Guardz Dirt Lock Pad Washer","subtitle":"Product Overview"},{"url":"https://www.youtube.com/embed/WCA-glSygO8","title":"Detail Guardz Dirt Lock Pad Washer New Improved","subtitle":"Product Overview"}]}', 'Detailing-Accessories', '12d2523b-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ', NULL, 'USA-DAB3B5F6', 'USA-DAB3B5F6', NULL, NULL, '4.00', 69, 1, 'In Stock', NULL, NULL, '["Patented venturi spring design pumps clean water into your buffing pads and squeezes out the dirty chemicals several times per second. Dramatically extends the pad life!","Gently cleans polishing pads within 10-15 seconds. Attaches into your Dirt Lock bucket filter (Sold separately).","Includes a storage bracket to neatly hang the kit when finished!","Cleans polishing pads gently and extremely quick! Good for ALL microfiber, foam, wool and other polishing pads from 1-10 inches!","Includes a 650ML bottle of our pad cleaner solution!"]', '["Dirt Lock Bucket Filter","All Polishing Pads 1\"–10\"","Foam Pads","Wool Pads","Microfiber Pads"]', '{"asin":"B07VGMKW7S","brand":"DETAIL GUARDZ","weight":"3.31 pounds","material":"Industrial Grade Plastic & Metal","dimensions":"8 x 8 x 15 inches","manufacturer":"DETAIL GUARDZ Canada","bestSellersRank":"#253,754 in Automotive, #674 in Body Repair Buffing & Polishing Pads","dateFirstAvailable":"September 16, 2019"}', '{"heroImage":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section large.jpg","description":"The Dirt Lock pad washer attachment clicks into your Dirt Lock bucket filter to clean any polishing pads safely and gently within seconds! Clean your foam, wool, microfiber, buffing bonnets and more within the blink of an eye. HOW TO USE: Simply insert the pad washer attachment into your Dirt Lock bucket filter and place into a bucket with clean water. Attach your dirty pads onto the supplied hook and loop handle and pump up and down on the attachment for about 15-20 seconds. Clean water will blast inside the pad and flush our any unwanted chemicals to create a perfectly clean polishing pad! The Dirt Lock pad washer attachment is made from industrial grade plastic and metal for extreme durability. The Detail Guardz Dirt Lock pad washer system is an extremely effective way to clean all your polishing pads gently, quickly and thoroughly within seconds. Works with ALL polishing pads and is extremely safe and gentle to prolong the life of the pad! Proudly Made In Canada.","heroImageAlt":"Dirt Lock Pad Washer System","secondarySection":{"items":[{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 1.jpg","title":"DIRT LOCK PAD WASHER SYSTEM ATTACHMENT","description":"Clean your polishing pads safely and gently within seconds! Simply attach the pad washer attachment into your Dirt Lock bucket filter, place your dirty pads onto the supplied hook and loop handle, spray with our pad cleaner to break down polish and wax, pump pads on the attachment and your done within seconds!"},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 2.jpg","title":"DIRT LOCK SCRUB AND PUMP SYSTEM ATTACHMENT","description":"Use the Scrub And Pump attachment for added cleaning power with your Dirt Lock bucket filter. Simply push the attachment into place and use it to scrub wash mitts, brushes, hand applicator pads and more! The Dirt Lock scrub and pump attachment works on a spring loaded system to pump cleaner water up and cycle dirty debris safely underneath the screen and out of harms way."},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 3.jpg","title":"DIRT LOCK SCRUB WALL 180/360 SYSTEM ATTACHMENT","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall."}],"title":"ATTACH AND EXPAND YOUR DIRT LOCK SYSTEM"}}', '[{"sku":"