-- DETAIL GUARDZ Hose Guide – Tire Wheel Rolling System Preventing Stucking and Snagging Under Tires (USA)
INSERT INTO products (
  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12dc4797-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ Hose Guide – Tire Wheel Rolling System Preventing Stucking and Snagging Under Tires', NULL, 'hose-roller-4-pack', '19.99', NULL, NULL, NULL, 'Tire-mounted hose rollers that slide under your vehicle to prevent hose & cord snags while detailing — universal fit with secure locking grip, 4-pack, made in Canada.', NULL, 'DETAIL GUARDZ CAR HOSE GUIDES

Using a set of Detail Guardz is the most efficient way to work around your vehicle without being interrupted by stubborn hose & cord jams. The roller system allows for effortless movements without the need to tug and adjust your equipment. This unique tool has a locking mechanism to instantly grip onto the tire to keep it firmly in place. Quickly slide the Detail Guardz underneath your tires and forget about your hoses and cords getting caught!

LINE GUIDANCE: If a hose or cable slides above the Detail Guardz, it is guided down the rounded tip and back onto the roller. This ensures you are never interrupted!

UNIVERSAL FIT: The Detail Guardz car hose guides will fit just about any size tire!

MADE IN CANADA: Detail Guardz are manufactured in Canada from industrial grade plastic and metal. Each unit is hand checked for the highest standards of quality!

ANTI-JAM: You can have several cables or hoses running at the same time and it will still work perfectly! The 2 rollers are independently spinning and therefore never jam-up!', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/1. Hero Image.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/2. Product features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/3. How It Works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/5. Product Uses.webp"]', '{"red":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Red/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Red/2. Product features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Red/3. How It Works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Red/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Red/5. Product Uses.webp"],"blue":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Blue/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Blue/2. Product features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Blue/3. How It Works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Blue/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Blue/5. Product Uses.webp"],"neon":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Neon/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Neon/2. Product features.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Neon/3. How It Works.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Neon/4. Product Fitting & Dimensions.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Neon/5. Product Uses.webp"],"black":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-20260122T171823Z-1-001/4-Pack Hose Guide/Black/1. Hero Image.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/4-Pack Hose Guide-202601