-- The Detail Guardz - Dirt Lock Pad Washer System Attachment (Black) (USA)
INSERT INTO products (
  id, name, name_ar, slug, price, original_price, discount, short_description, description, description_ar, long_description, image, images, variant_images, youtube_url, videos, category, category_id, brand, brand_id, sku, amazon_sku, asin, amazon_url, rating, review_count, in_stock, availability, weight_kg, dimensions, features, compatibility, specifications, about_section, color_options, reviews, rating_breakdown, badge, url, tags, sizes, country, inventory_cache, target_country, hide_for_usa, is_active, created_at, updated_at
) VALUES (
  '12dcee12-2b91-11f1-ac48-767b5e3bd9b8', 'The Detail Guardz - Dirt Lock Pad Washer System Attachment (Black)', NULL, 'dirt-lock-pad-washer-system-attachment-black', '49.99', NULL, NULL, NULL, 'The ultimate pad washing kit! Includes everything you need to clean your polishing pads quickly and gently.', NULL, 'The Detail Guardz Dirt Lock pad washer system is an extremely effective way to clean all your polishing pads gently, quickly and thoroughly within seconds. This complete kit includes everything you need to maintain your pads and keep your wash water clean. Works with ALL polishing pads and is extremely safe and gentle to prolong the life of the pad! Proudly Made In Canada.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/black.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/white.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/black.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/1.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/2.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/3.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/4.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/5.webp"]', '{"black":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/black.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/1.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/2.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/3.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/4.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/5.webp"],"white":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/white.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/1.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/2.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/3.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/4.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/5.webp"]}', NULL, '{"main":{"url":"https://www.youtube.com/embed/_ZHI-xV6XLg","title":"DETAIL GUARDZ Dirt Lock Pad Washer System","description":"The complete guide to using the Pad Washer system with the Dirt Lock filter."},"additional":[{"url":"https://www.youtube.com/embed/rmmq1jVdY40","title":"How To PROPERLY Clean Pads","subtitle":"Complete Guide"}]}', 'Detailing-Accessories', '12d2523b-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ', NULL, 'USA-69861DC8', 'USA-69861DC8', NULL, NULL, '4.80', 51, 0, 'Out of Stock', NULL, NULL, '["Dirt Lock bucket filter","Pad washer attachment","Hook and loop handle","Storage bracket","Quickly and gently cleans any polishing pad within seconds","Dramatically extends the life of your polishing pads"]', '["3-8 Gallon Round Pails"]', '{"brand":"DETAIL GUARDZ","weight":"3.5 pounds","material":"Industrial Grade Plastic & Metal","dimensions":"8 x 8 x 15 inches","manufacturer":"DETAIL GUARDZ Canada"}', '{"heroImage":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/about section large.jpg","description":"The Dirt Lock pad washer attachment clicks into your Dirt Lock bucket filter to clean any polishing pads safely and gently within seconds! Clean your foam, wool, microfiber, buffing bonnets and more within the blink of an eye. HOW TO USE: Simply insert the pad washer attachment into your Dirt Lock bucket filter and place into a bucket with clean water. Attach your dirty pads onto the supplied hook and loop handle and pump up and down on the attachment for about 15-20 seconds. Clean water will blast inside the pad and flush our any unwanted chemicals to create a perfectly clean polishing pad! The Dirt Lock pad washer attachment is made from industrial grade plastic and metal for extreme durability. The Detail Guardz Dirt Lock pad washer system is an extremely effective way to clean all your polishing pads gently, quickly and thoroughly within seconds. Works with ALL polishing pads and is extremely safe and gentle to prolong the life of the pad! Proudly Made In Canada.","heroImageAlt":"Dirt Lock Pad Washer System","secondarySection":{"items":[{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 1.jpg","title":"DIRT LOCK PAD WASHER SYSTEM ATTACHMENT","description":"Clean your polishing pads safely and gently within seconds! Simply attach the pad washer attachment into your Dirt Lock bucket filter, place your dirty pads onto the supplied hook and loop handle, spray with our pad cleaner to break down polish and wax, pump pads on the attachment and your done within seconds!"},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 2.jpg","title":"DIRT LOCK SCRUB AND PUMP SYSTEM ATTACHMENT","description":"Use the Scrub And Pump attachment for added cleaning power with your Dirt Lock bucket filter. Simply push the attachment into place and use it to scrub wash mitts, brushes, hand applicator pads and more! The Dirt Lock scrub and pump attachment works on a spring loaded system to pump cleaner water up and cycle dirty debris safely underneath the screen and out of harms way."},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 3.jpg","title":"DIRT LOCK SCRUB WALL 180/360 SYSTEM ATTACHMENT","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall."}],"title":"ATTACH AND EXPAND YOUR DIRT LOCK SYSTEM"}}', '[{"sku":"DIRT-LOCK-PWS-BLACK","url":"https://www.amazon.com/Detail-Guardz-Attachment-Without-Cleaner/dp/B07XL4CL1T/ref=pd_cer_fm_1/135-9153945-0013018?pd_rd_r=457f8f31-4d35-4d41-86e7-f8ad048dcd17&pd_rd_wg=vU41E&pd_rd_w=ynUdM&pd_rd_i=B07XL4CL1T&th=1","asin":"B07XL4CL1T","name":"Black","fnsku":"X002B6QOON","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/black.webp","price":49.99,"stock":0,"title":"The Detail Guardz - Dirt Lock Pad Washer System Attachment (Black)","value":"black","in_stock":0,"amazon_sku":"DIRT-LOCK-PWS-BLACK"},{"sku":"DIRT-LOCK-PWS-WHITE-1","url":"https://www.amazon.com/Detail-Guardz-Attachment-Without-Cleaner/dp/B08KTVWVMJ/ref=pd_cer_fm_1/135-9153945-0013018?pd_rd_r=457f8f31-4d35-4d41-86e7-f8ad048dcd17&pd_rd_wg=vU41E&pd_rd_w=ynUdM&pd_rd_i=B07XL4CL1T&th=1","asin":"B08KTVWVMJ","name":"White","fnsku":"X002O8MDE3","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Pad Washer Images/white.webp","price":49.99,"stock":0,"title":"DETAIL GUARDZ The Dirt Lock Pad Washer System Attachment (White)","value":"white","in_stock":0,"amazon_sku":"DIRT-LOCK-PWS-WHITE-1"}]', '[{"date":"2 days ago","name":"John Doe","title":"Perfect Product!","images":["https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1519641471654-76ce0107ad1b?w=200&h=200&fit=crop"],"rating":5,"comment":"This is hands down the best car care product I''ve ever purchased. The quality is exceptional and it works exactly as advertised. Installation was super easy and it''s made such a difference in my detailing routine. Highly recommend to anyone serious about car care!","verified":1,"helpfulCount":24},{"date":"1 week ago","name":"Sarah Miller","title":"Great value for money","rating":4,"comment":"Really impressed with the quality. Works great and is very durable. The only reason I''m giving 4 stars instead of 5 is that shipping took a bit longer than expected, but the product itself is fantastic. Would definitely buy again.","verified":1,"helpfulCount":12},{"date":"2 weeks ago","name":"Mike Rodriguez","title":"Professional Quality","images":["https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?w=200&h=200&fit=crop"],"rating":5,"comment":"As a professional detailer, I''m always skeptical of new products. But this exceeded my expectations. The build quality is solid, it performs consistently, and my clients have noticed the difference. Already ordered 3 more for my team. A must-have tool!","verified":1,"helpfulCount":45},{"date":"3 weeks ago","name":"Emily Kim","title":"Exceeded expectations!","rating":5,"comment":"I was hesitant to spend this much on a car care product, but I''m so glad I did. It''s made my weekly car washing so much easier and more effective. The results speak for themselves - my car looks showroom fresh every time. Worth every penny!","verified":1,"helpfulCount":18}]', '[{"count":423,"stars":5,"percentage":75},{"count":85,"stars":4,"percentage":15},{"count":34,"stars":3,"percentage":6},{"count":17,"stars":2,"percentage":3},{"count":5,"stars":1,"percentage":1}]', 'Premium', NULL, NULL, NULL, 'USA', 0, 'us', 0, 1, '"2026-03-29T22:32:31.000Z"', '"2026-04-01T23:47:02.000Z"'
);

