  '12e00b96-2b91-11f1-ac48-767b5e3bd9b8', 'DIRT LOCK - COMPLETE SCRUB WALL KIT', NULL, 'cad-scrub-wall-kit', '59.99', NULL, NULL, NULL, 'Vertical extension of the Dirt Lock’s pressurized cleaning power.', NULL, 'The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock’s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more. Made In Canada.', 'https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-Black_MainImage_ae9fb235-7709-48d4-a81a-03b3cf45c222_720x.webp', '["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-Black_MainImage_ae9fb235-7709-48d4-a81a-03b3cf45c222_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BLACK-BLACK_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BLACK_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BlackCloseUp_4f137138-8e7d-4738-be0f-3a2ba3646f67_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180_WHITE_-MainImage_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW360_WHITE_-MainImage-WithDirtLock_720x.webp"]', '{"black":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-Black_MainImage_ae9fb235-7709-48d4-a81a-03b3cf45c222_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BLACK-BLACK_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BLACK_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-BlackCloseUp_4f137138-8e7d-4738-be0f-3a2ba3646f67_720x.webp"],"white":["https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180_WHITE_-MainImage_720x.webp","https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW360_WHITE_-MainImage-WithDirtLock_720x.webp"]}', NULL, '{"main":{"url":"https://www.youtube.com/embed/wgR1NE6h6Zk","title":"DETAIL GUARDZ Dirt Lock Scrub Wall 180/360","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock''s pressurized cleaning power."},"additional":[{"url":"https://www.youtube.com/embed/2S1_ebwMuZs","title":"Scrub Wall In Action","subtitle":"Vertical cleaning technology"},{"url":"https://www.youtube.com/embed/dgeAFI_K6sI","title":"Scrub Wall Teaser","subtitle":"Product highlights"}]}', 'Kit-Bundle', '12d25543-2b91-11f1-ac48-767b5e3bd9b8', 'DETAIL GUARDZ', NULL, 'CAD-A49E3167', 'CAD-A49E3167', NULL, NULL, '4.60', 34, 1, 'In Stock', NULL, NULL, '["180° Coverage (expandable to 360°)","Vertical cleaning surface","Snaps into Dirt Lock filter"]', '["Dirt Lock Bucket Filter","3-8 Gallon Pails"]', '{"brand":"DETAIL GUARDZ","weight":"525 Grams","material":"High-Grade Plastic Resin","dimensions":"10.43\"L x 10.43\"W x 2.56\"H","manufacturer":"DETAIL GUARDZ Canada"}', '{"features":[{"alt":"Vertical Cleaning Power","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL.jpg","label":"VERTICAL EXTENSION OF THE DIRT LOCK''S PRESSURIZED CLEANING POWER","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock''s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space."},{"alt":"Attaches Into Filter","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL 1.jpg","label":"ATTACHES INTO DIRT LOCK BUCKET FILTER","description":"The Dirt Lock bucket filter allows you to attach the Scrub Wall 180/360 or any of our other detailing tools when needed. When your finished, simply detach it!\n\nEach Scrub Wall kit contains 180 degrees of coverage, simply connect two 180 kits together for full 360 degree bucket coverage."},{"alt":"Advanced Filtering","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION SMALL 2.jpg","label":"OUR MOST ADVANCED BUCKET FILTERING SYSTEM","description":"The Dirt Lock bucket filter is extremely powerful on it''s own. With the addition of our scrub wall 180/360 attachment, it takes the product to another level by flushing out your wash mitt and tools more thoroughly, resulting in even cleaner wash media and the ability to cycle the debris even quicker underneath the screen."}],"heroImage":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Scrub Wall-20260122T171828Z-1-001/ABOUT SECTION LARGE.jpg","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock''s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall. The debris is now behind the scrub wall screen and is pumped and trapped below the filter to provide cleaner, filtered water for reuse.","heroImageAlt":"Dirt Lock Scrub Wall System","secondarySection":{"items":[{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 1.jpg","title":"DIRT LOCK PAD WASHER SYSTEM ATTACHMENT","description":"Clean your polishing pads safely and gently within seconds! Simply attach the pad washer attachment into your Dirt Lock bucket filter, place your dirty pads onto the supplied hook and loop handle, spray with our pad cleaner to break down polish and wax, pump pads on the attachment and your done within seconds!"},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 2.jpg","title":"DIRT LOCK SCRUB AND PUMP SYSTEM ATTACHMENT","description":"Use the Scrub And Pump attachment for added cleaning power with your Dirt Lock bucket filter. Simply push the attachment into place and use it to scrub wash mitts, brushes, hand applicator pads and more! The Dirt Lock scrub and pump attachment works on a spring loaded system to pump cleaner water up and cycle dirty debris safely underneath the screen and out of harms way."},{"image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Amazon Listing Images/Dirt Lock-20260122T171825Z-1-001/ATTACH AND EXPAND SECTION 3.jpg","title":"DIRT LOCK SCRUB WALL 180/360 SYSTEM ATTACHMENT","description":"The Dirt Lock Scrub Wall attachment is a vertical extension of the Dirt Lock''s pressurized cleaning power. Simply snap the attachment into your Dirt Lock bucket filter to easily clean your wheel brushes, wash mitts and more without having to sacrifice hardly any bucket space. Simply scrub your wash media on the side of the Scrub Wall."}],"title":"ADDITIONAL ATTACHMENTS"}}', '[{"sku":"CAD-A49E3167-V-BLACK","name":"Black","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180-Black_MainImage_ae9fb235-7709-48d4-a81a-03b3cf45c222_720x.webp","price":59.99,"value":"black","amazon_sku":"CAD-A49E3167-V-BLACK"},{"sku":"CAD-A49E3167-V-WHITE","name":"White","image":"https://detailguardz.s3.us-east-1.amazonaws.com/assets/Canada Products/DIRT LOCK - COMPLETE SCRUB WALL KIT/DIRTLOCK-SW180_WHITE_-MainImage_720x.webp","price":59.99,"value":"white","amazon_sku":"CAD-A49E3167-V-WHITE"}]', '[{"date":"2 days ago","name":"John Doe","title":"Perfect Product!","images":["https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=200&h=200&fit=crop","https://images.unsplash.com/photo-1519641471654-76ce0107ad1b?w=200&h=200&fit=crop"],"rating":5,"comment":"This is hands down the best car care product I''ve ever purchased. The quality is exceptional and it works exactly as advertised. Installation was super easy and it''s made such a difference in my detailing routine. Highly recommend to anyone serious about car care!","verified":1,"helpfulCount":24},{"date":"1 week ago","name":"Sarah Miller","title":"Great value for money","rating":4,"comment":"Really impressed with the quality. Works great and is very durable. The only reason I''m giving 4 stars instead of 5 is that shipping took a bit longer than expected, but the product itself is fantastic. Would definitely buy again.","verified":1,"helpfulCount":12},{"date":"2 weeks ago","name":"Mike Rodriguez","title":"Professional Quality","images":["https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?w=200&h=200&fit=crop"],"rating":5,"comment":"As a professional detailer, I''m always skeptical of new products. But this exceeded my expectations. The build quality is solid, it performs consistently, and my clients have noticed the difference. Already ordered 3 more for my team. A must-have tool!","verified":1,"helpfulCount":45},{"date":"3 weeks ago","name":"Emily Kim","title":"Exceeded expectations!","rating":5,"comment":"I was hesitant to spend this much on a car care product, but I''m so glad I did. It''s made my weekly car washing so much easier and more effective. The results speak for themselves - my car looks showroom fresh every time. Worth every penny!","verified":1,"helpfulCount":18}]', '[{"count":423,"stars":5,"percentage":75},{"count":85,"stars":4,"percentage":15},{"count":34,"stars":3,"percentage":6},{"count":17,"stars":2,"percentage":3},{"count":5,"stars":1,"percentage":1}]', 'Premium', NULL, NULL, NULL, 'CAD', 0, 'canada', 0, 1, '"2026-03-29T22:32:31.000Z"', '"2026-04-01T23:45:45.000Z"'
